final:
module RefModule (
        gin, 
        bout
);

parameter width = 6;

input  [width-1 : 0] gin;
output [width-1 : 0] bout;

reg    [width-1 : 0] unused_breg;
integer i;
assign bout = unused_breg;

always @(gin)
begin
    unused_breg[width-1] = gin[width-1];
    if (width > 1)
    begin
        for (i=width-2; i >= 0; i=i-1)
            unused_breg[i] = unused_breg[i+1] ^ gin[i];
    end
end

endmodule
